import React, { useState, useEffect } from 'react';
import './A';
import { BrowserRouter as Router, Routes, Route, Outlet, Link, useNavigate, useLocation } from 'react-router-dom';
import { FaSignOutAlt, FaPlus, FaHome, FaBook, FaUser, FaGithub, FaTwitter, FaLinkedin } from 'react-icons/fa';

function Layout({ user }) {
  const navigate = useNavigate();
  const location = useLocation();
  const [particles, setParticles] = useState([]);

  useEffect(() => {
    // Create floating particles
    const newParticles = Array.from({ length: 15 }, (_, i) => ({
      id: i,
      size: Math.random() * 10 + 5,
      left: Math.random() * 100,
      top: Math.random() * 100,
      animationDuration: Math.random() * 20 + 10,
      delay: Math.random() * 5
    }));
    setParticles(newParticles);
  }, []);

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    navigate('/login');
  };

  const getInitials = (name) => {
    return name ? name.split(' ').map(n => n[0]).join('').toUpperCase() : '?';
  };

  return (
    <div className="app-container">
      {/* Floating particles background */}
      <div className="particles">
        {particles.map(particle => (
          <div 
            key={particle.id}
            className="particle"
            style={{
              width: `${particle.size}px`,
              height: `${particle.size}px`,
              left: `${particle.left}%`,
              top: `${particle.top}%`,
              animation: `float ${particle.animationDuration}s ${particle.delay}s infinite linear`
            }}
          />
        ))}
      </div>

      {/* Header */}
      <header className="app-header">
        <div className="header-content">
          <div className="logo-container" onClick={() => navigate('/dashboard')}>
            <div className="math-symbol">∫</div>
            <h1 className="app-title">Math<span className="highlight">iQ</span></h1>
          </div>

          {/* Navigation */}
          <nav className="nav-links">
            <Link 
              to="/dashboard" 
              className={`nav-link ${location.pathname === '/dashboard' ? 'active' : ''}`}
            >
              <FaHome /> Dashboard
            </Link>
            <Link 
              to="/problems" 
              className={`nav-link ${location.pathname.startsWith('/problems') ? 'active' : ''}`}
            >
              <FaBook /> Problems
            </Link>
            {user?.role === 'admin' && (
              <Link 
                to="/create-problem" 
                className={`nav-link ${location.pathname === '/create-problem' ? 'active' : ''}`}
              >
                <FaPlus /> Create
              </Link>
            )}
          </nav>

          {/* User Info */}
          {user && (
            <div className="user-info">
              <span className="welcome-message">Welcome back, {user.username}</span>
              <div className="user-avatar" title={user.username}>
                {getInitials(user.username)}
              </div>
              <button className="logout-btn" onClick={handleLogout}>
                <FaSignOutAlt /> Logout
              </button>
            </div>
          )}
        </div>
      </header>

      {/* Main Content */}
      <main className="app-main">
        <Outlet />
      </main>

      {/* Footer */}
      <footer className="app-footer">
        <div className="footer-content">
          <p>&copy; 2025 MathiQ | Visualizing Mathematical Beauty</p>
          <div className="social-links">
            <a href="https://github.com" className="social-link" target="_blank" rel="noopener noreferrer">
              <FaGithub />
            </a>
            <a href="https://twitter.com" className="social-link" target="_blank" rel="noopener noreferrer">
              <FaTwitter />
            </a>
            <a href="https://linkedin.com" className="social-link" target="_blank" rel="noopener noreferrer">
              <FaLinkedin />
            </a>
          </div>
        </div>
      </footer>

      {/* Floating action button for mobile */}
      {user?.role === 'admin' && (
        <div className="fab" onClick={() => navigate('/create-problem')} title="Create Problem">
          <FaPlus />
        </div>
      )}
    </div>
  );
}
